 54→    negative: 0,
 55→  };
 56→  overallSentiment.negative = 100 - overallSentiment.positive - overallSentiment.neutral;
 57→  if (overallSentiment.negative < 0) {
 58→    overallSentiment.neutral += overallSentiment.negative;
 59→    overallSentiment.negative = 0;
 60→  }
 61→
 62→  // ── Engine results ──
 63→  const engines: AIEngine[] = ['ChatGPT', 'Claude', 'Perplexity', 'Gemini', 'AI Overviews'];
 64→  const queryPool = [
