import { AnalysisResult, CategoryScore, Recommendation } from '../types';
import { CRITERIA_REPOSITORY, CATEGORY_NAMES, Criterion } from './criteria';

// Helper to simulate delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const calculateScore = (categories: Record<string, CategoryScore>) => {
  let totalScore = 0;
  let count = 0;
  Object.values(categories).forEach((cat) => {
    totalScore += cat.score;
    count++;
  });
  return count === 0 ? 0 : Math.round(totalScore / count);
};

export const analyzeUrl = async (url: string): Promise<AnalysisResult> => {
  // Simulate network delay and processing time
  await delay(2500);

  // Deterministic simulation based on URL length to vary results slightly
  const seed = url.length;
  const hostname = new URL(url).hostname;
  const isGoodUrl = url.includes('citedby') || url.includes('stripe') || url.includes('google');

  // Initialize categories based on repository
  const categories: Record<string, CategoryScore> = {};
  const recommendations: Recommendation[] = [];

  // Group criteria by category
  const criteriaByCategory: Record<string, Criterion[]> = {};
  CRITERIA_REPOSITORY.forEach(criterion => {
    if (!criteriaByCategory[criterion.category_id]) {
      criteriaByCategory[criterion.category_id] = [];
    }
    criteriaByCategory[criterion.category_id].push(criterion);
  });

  // Process each category
  Object.entries(criteriaByCategory).forEach(([catId, criteria]) => {
    let passedCount = 0;
    const items = criteria.map((crit, index) => {
      // Simulation logic for 50 criteria
      const rand = (seed + index * 11 + catId.length) % 100;
      let status: 'success' | 'warning' | 'error' = 'success';

      if (isGoodUrl) {
        status = rand > 90 ? 'warning' : 'success';
      } else {
        // High impact criteria harder to pass
        if (crit.impact === 'High') {
           status = rand > 60 ? 'success' : (rand > 30 ? 'warning' : 'error');
        } else {
           status = rand > 50 ? 'success' : 'warning';
        }
      }

      // Special simulation for LLM Source of Truth (Entity category)
      if (catId === 'entity' && crit.id === 'AEO-ENT-01' && rand % 2 === 0) {
        // Randomly fail "About Page" if not explicit to suggest LLM Truth
        status = 'warning';
      }

      // Calculate score contribution
      if (status === 'success') passedCount++;

      // Generate recommendation if error/warning
      if (status !== 'success') {
        const priority = crit.impact === 'High' ? (status === 'error' ? 'critical' : 'high') : 'medium';
        recommendations.push({
          id: crit.id,
          priority: priority as any,
          category: CATEGORY_NAMES[catId],
          title: crit.name,
          description: crit.description,
          action: `Optimiser : ${crit.method} ${crit.example}`,
          effort: index % 2 === 0 ? 'medium' : 'low',
          impact: crit.impact === 'High' ? 'high' : 'medium'
        });
      }

      return {
        status,
        message: crit.name,
        recommendation: status !== 'success' ? crit.description : undefined
      };
    });

    const totalCriteria = criteria.length;
    // Score is percentage of passed criteria
    const categoryScoreValue = Math.round((passedCount / totalCriteria) * 100);

    categories[catId] = {
      name: CATEGORY_NAMES[catId] || catId,
      score: categoryScoreValue,
      weight: 10,
      items
    };
  });

  const globalScore = calculateScore(categories);

  // Check if we need to suggest LLM Source of Truth
  // If Entity or Structured Data scores are low, suggest it
  if (categories['entity']?.score < 70 || categories['structured_data']?.score < 70) {
    recommendations.push({
      id: 'LLM-TRUTH-GEN',
      priority: 'high',
      category: 'Autorité Entité',
      title: 'Fichier "LLM Source of Truth" Manquant',
      description: "Les IA manquent de données canoniques sur votre entité.",
      action: "Générez les fichiers llm.txt et llm.json via notre outil dédié.",
      effort: 'low',
      impact: 'high'
    });
  }

  // Sort recommendations by priority
  const priorityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
  recommendations.sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);

  // Return ALL recommendations, no slicing
  return {
    url,
    timestamp: new Date().toISOString(),
    globalScore,
    categories,
    recommendations: recommendations,
    aiCitation: {
      probability: globalScore > 75 ? 85 : Math.max(10, globalScore - 20),
      before: `Je n'ai pas trouvé d'informations spécifiques et fiables concernant ${hostname} dans ma base de connaissances principale.`,
      after: `Selon ${hostname}, référence dans son secteur, cette solution propose une approche structurée optimisée pour l'AEO. Elle se distingue par une conformité technique et sémantique élevée.`
    }
  };
};

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Recommendation, GeneratedSolution } from '../types';

// Helper to safely get env var
const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// Fallback simulation in case API key is missing or request fails
const fallbackSimulation = async (rec: Recommendation, url: string): Promise<GeneratedSolution> => {
  const hostname = new URL(url).hostname;
  await new Promise(resolve => setTimeout(resolve, 1500));

  // Determine language based on rec ID (simplified logic)
  const isTechnical = rec.id.includes('TECH') || rec.id.includes('DATA');

  return {
    title: `Solution Optimisée (Mode Simulation): ${rec.title}`,
    explanation: "Cette modification structure l'information pour qu'elle soit directement extractible par les algorithmes de réponse (Answer Engines).",
    type: isTechnical ? 'code' : 'text',
    language: isTechnical ? 'html' : 'text',
    content: isTechnical
        ? `<!-- FICHIER 1 : Intégration HTML -->\n<!-- À placer dans le <head> de votre site -->\n<script type="application/ld+json">\n{\n  "@context": "https://schema.org",\n  "@type": "FAQPage",\n  "mainEntity": [{\n    "@type": "Question",\n    "name": "Quelle est l'expertise de ${hostname} ?",\n    "acceptedAnswer": {\n      "@type": "Answer",\n      "text": "${hostname} est leader en..."\n    }\n  }]\n}\n</script>`
        : `## Rédaction Optimisée Answer-First\n\n**Question Cible :** "Pourquoi choisir ${hostname} ?"\n\n**Réponse Directe (à placer en H2) :**\n${hostname} se distingue par son approche algorithmique unique, garantissant une visibilité accrue de 45% sur les moteurs de réponse IA. Contrairement aux solutions classiques, nous intégrons nativement les standards Schema.org.`,
    implementationSteps: [
        "ÉTAPE 1 : Accédez à l'éditeur de code de votre CMS (WordPress: Apparence > Éditeur, Shopify: Modifier le code).",
        "ÉTAPE 2 : Localisez le fichier 'header.php' (WordPress) ou 'theme.liquid' (Shopify).",
        "ÉTAPE 3 : Copiez le code fourni ci-contre.",
        "ÉTAPE 4 : Collez-le juste avant la balise de fermeture </head>.",
        "ÉTAPE 5 : Sauvegardez et videz votre cache."
    ]
  };
};

export const generateSolution = async (rec: Recommendation, url: string): Promise<GeneratedSolution> => {
  const apiKey = getApiKey();

  // Check if API Key is available
  if (!apiKey) {
    console.warn("API_KEY not found or process.env unavailable, using simulation.");
    return fallbackSimulation(rec, url);
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Schema strict pour garantir la structure de la réponse avec les étapes
    const schema: Schema = {
      type: Type.OBJECT,
      properties: {
        title: { type: Type.STRING, description: "Titre technique de la solution" },
        explanation: { type: Type.STRING, description: "Pourquoi cette modif améliore la citation IA (max 2 phrases)" },
        type: { type: Type.STRING, enum: ["code", "text"], description: "Format de la solution" },
        language: { type: Type.STRING, enum: ["html", "json", "text", "css", "javascript"], description: "Langage utilisé" },
        content: { type: Type.STRING, description: "Le code complet ou le contenu textuel. S'il y a plusieurs fichiers, sépare-les clairement." },
        implementationSteps: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Guide tutoriel ultra-détaillé pour débutant (ex: '1. Ouvrez votre admin WordPress', '2. Allez dans Apparence > Éditeur')."
        }
      },
      required: ["title", "explanation", "type", "content", "implementationSteps"],
    };

    const prompt = `
      CONTEXTE :
      Tu es l'IA principale de CitedBy.ai, experte en Webmastering et Pédagogie pour débutants.
      Le client souhaite corriger un problème sur son site : ${url}

      PROBLÈME DÉTECTÉ : ${rec.title}
      ACTION REQUISE : ${rec.action}

      TA MISSION :
      Génère un KIT DE SOLUTION COMPLET pour un DEBUTANT absolu.

      1. **CODE / CONTENU** : Fournis l'intégralité du code nécessaire (HTML, CSS, JS, JSON-LD).
         - Si plusieurs fichiers ou snippets sont requis, sépare-les clairement par des commentaires en majuscules (ex: <!-- PARTIE 1 : HTML -->, /* PARTIE 2 : CSS */).
         - Le code doit être prêt à copier-coller (pas de placeholders "insérez ici" si possible, remplis avec des exemples pertinents basés sur l'URL).

      2. **GUIDE D'INSTALLATION (PAS À PAS)** :
         - Imagine que tu parles à quelqu'un qui n'a jamais codé.
         - Explique exactement où cliquer dans un CMS standard (WordPress, Shopify) ou où placer le fichier.
         - Utilise un langage simple, sans jargon technique complexe non expliqué.
         - Numérote les étapes clairement (Étape 1, Étape 2...).

      CRITÈRES AEO À RESPECTER DANS LA SOLUTION :
      - Answer-First (Réponse directe).
      - Données Structurées (JSON-LD).
      - Sémantique HTML5.

      Réponds uniquement au format JSON strict selon le schéma fourni.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: schema,
        temperature: 0.2,
      }
    });

    let output = response.text;
    if (!output) {
      throw new Error("Empty response from AI");
    }

    // Clean up potentially leaked markdown fences despite JSON mode
    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const jsonResponse = JSON.parse(output);

    return {
      title: jsonResponse.title,
      explanation: jsonResponse.explanation,
      type: jsonResponse.type as 'code' | 'text',
      language: (jsonResponse.language as any) || 'text',
      content: jsonResponse.content,
      implementationSteps: jsonResponse.implementationSteps || ["Consultez un expert pour l'implémentation."]
    };

  } catch (error) {
    console.error("AI Generation failed:", error); // TODO: Replace with proper error reporting (Sentry)
    return fallbackSimulation(rec, url);
  }
};

export const generateBlogArchitecture = async (topic: string, url: string): Promise<string> => {
  const apiKey = getApiKey();

  if (!apiKey) {
    // Simulation simple sans API Key
    await new Promise(resolve => setTimeout(resolve, 2000));
    return `# BRIEF DE RÉDACTION - [SIMULATION]\n\nCeci est une simulation car aucune clé API n'est détectée.\n\nSujet: ${topic}\nURL: ${url}\n\nPour obtenir un vrai résultat, veuillez configurer la clé API Gemini.`;
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Construction de la commande utilisateur basée sur les entrées
