      tips: semanticHtmlScore >= 60
        ? [
            "Remplacer les <div> generiques par <article>, <section>, <aside> quand pertinent",
            "Ajouter <cite> pour les sources et references",
            "Utiliser <details>/<summary> pour le contenu accordeon"
          ]
        : [
            "Envelopper le contenu principal dans une balise <article>",
            "Utiliser <section> pour chaque bloc thematique avec un <h2> ou <h3>",
            "Ajouter <nav> pour les menus de navigation et les sommaires",
            "Implementer <details>/<summary> pour les FAQ et contenus depliables",
            "Ajouter <time datetime='...'> pour les dates de publication"
          ]
    },
    contentFreshness: {
      score: contentFreshnessScore,
      label: scoreToLabel(contentFreshnessScore),
      details: contentFreshnessScore >= 60
        ? `Le contenu de ${hostname} semble relativement a jour mais le schema dateModified n'est pas toujours present pour signaler les mises a jour recentes.`
        : `Le contenu de ${hostname} ne semble pas regulierement mis a jour. Aucune indication de dateModified ou de fraicheur du contenu pour les IA.`,
      tips: contentFreshnessScore >= 60
        ? [
            "Ajouter la propriete dateModified dans le schema Article/WebPage",
            "Afficher visuellement la date de derniere mise a jour sur la page",
            "Planifier une revue trimestrielle du contenu principal"
          ]
        : [
            "Ajouter datePublished et dateModified dans le schema JSON-LD",
            "Mettre a jour le contenu au moins tous les 3-6 mois",
            "Afficher clairement 'Derniere mise a jour : [date]' sur chaque page",
            "Creer un calendrier editorial pour maintenir le contenu frais",
            "Ajouter une section 'Actualites' ou 'Blog' avec du contenu recent"
          ]
    },
    metaOptimization: {
      score: metaOptimizationScore,
      label: scoreToLabel(metaOptimizationScore),
      details: metaOptimizationScore >= 60
        ? `Les meta tags de ${hostname} sont presents mais la meta description ne suit pas le format Answer-First. Le canonical et robots sont correctement configures.`
        : `Les meta tags de ${hostname} sont incomplets ou non optimises pour les moteurs de reponse IA. La meta description ne contient pas de reponse directe.`,
      tips: metaOptimizationScore >= 60
        ? [
            "Reformuler la meta description pour commencer par la reponse directe",
            "S'assurer que chaque page a un canonical unique",
            "Verifier que robots.txt n'empeche pas l'indexation IA (Googlebot, GPTBot)"
          ]
        : [
            "Rediger chaque meta description en format Answer-First (reponse directe dans les 60 premiers caracteres)",
            "Ajouter une balise canonical sur toutes les pages",
            "Verifier que robots.txt autorise GPTBot, Google-Extended et Anthropic",
            "Ajouter les meta tags og:title, og:description, og:type",
            "S'assurer que le <title> contient la question cible et la reponse concise"
          ]
    }
  };

  const globalScore = computeGlobalScore(categories);

  // Build top recommendations from lowest-scoring categories
  const sortedCategories = (Object.entries(categories) as [keyof typeof categories, CategoryResult][])
    .sort((a, b) => a[1].score - b[1].score);

  const topRecommendations = sortedCategories.slice(0, 3).map(([key, cat]) => {
    return cat.tips[0];
  });

  const summary = globalScore >= 70
    ? `${brand} presente un bon niveau de citabilite IA avec un score global de ${globalScore}/100. Des optimisations ciblees sur ${sortedCategories[0][1].label === 'Faible' || sortedCategories[0][1].label === 'Critique' ? 'les donnees structurees et le contenu Answer-First' : 'quelques aspects techniques'} permettraient d'atteindre l'excellence.`
    : globalScore >= 45
      ? `${brand} a un niveau de citabilite IA moyen (${globalScore}/100). Les IA peuvent extraire certaines informations mais le contenu n'est pas optimise pour etre cite en priorite. Des actions sur la structure FAQ, le Schema.org et le format Answer-First sont recommandees.`
      : `${brand} a un faible score de citabilite IA (${globalScore}/100). Le contenu n'est pas structure pour etre extrait par les moteurs de reponse IA. Une refonte de la strategie de contenu est necessaire : reponses directes, donnees structurees et balisage semantique.`;

  return {
    globalScore,
    url,
    categories,
    summary,
    topRecommendations
  };
};

// ================================================================
// GEMINI API SCHEMA
// ================================================================

const buildResponseSchema = (): Schema => {
  const categorySchema: Schema = {
    type: Type.OBJECT,
    properties: {
      score: { type: Type.NUMBER, description: "Score de 0 a 100" },
      label: { type: Type.STRING, description: "Label qualitatif : Critique, Faible, Moyen, Bon, Excellent" },
      details: { type: Type.STRING, description: "Explication detaillee de l'evaluation pour cette categorie" },
      tips: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Liste de conseils actionables pour ameliorer cette categorie"
      }
    },
    required: ["score", "label", "details", "tips"]
  };

  return {
    type: Type.OBJECT,
    properties: {
      globalScore: { type: Type.NUMBER, description: "Score global de citabilite IA de 0 a 100 (moyenne ponderee)" },
      summary: { type: Type.STRING, description: "Resume global de l'audit en 2-3 phrases" },
      topRecommendations: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Top 3-5 recommandations prioritaires"
      },
      categories: {
        type: Type.OBJECT,
        properties: {
          answerFirst: categorySchema,
          schemaOrg: categorySchema,
          faqStructure: categorySchema,
          semanticHtml: categorySchema,
          contentFreshness: categorySchema,
          metaOptimization: categorySchema,
        },
        required: ["answerFirst", "schemaOrg", "faqStructure", "semanticHtml", "contentFreshness", "metaOptimization"]
      }
    },
    required: ["globalScore", "summary", "topRecommendations", "categories"]
  };
};

