// PROMPT
// ================================================================

const AUDIT_SYSTEM_PROMPT = `
# ROLE
Tu es un Expert en AEO (Answer Engine Optimization) et en citabilite IA chez CitedBy.ai.

# MISSION
Audite une URL pour evaluer sa "citabilite" par les moteurs de reponse IA (ChatGPT, Perplexity, Gemini, Claude, Copilot).

# CATEGORIES D'EVALUATION (avec poids)

1. **answerFirst** (25%) : La reponse directe est-elle dans les 100 premiers mots ? Format inverted pyramid ?
2. **schemaOrg** (20%) : Presence de JSON-LD (Organization, Article, FAQPage, BreadcrumbList, HowTo) ?
3. **faqStructure** (15%) : Sections FAQ avec format Question/Reponse clair et balisage ?
4. **semanticHtml** (15%) : Utilisation de <article>, <section>, <details>, <cite>, <time>, <nav> ?
5. **contentFreshness** (10%) : Presence de dateModified, contenu recent, frequence de mise a jour ?
6. **metaOptimization** (15%) : Meta description answer-first, canonical, robots.txt (GPTBot, Anthropic) ?

# REGLES
- Score global = moyenne ponderee selon les poids ci-dessus
- Chaque score de 0 a 100, avec label : Critique (<20), Faible (20-39), Moyen (40-59), Bon (60-79), Excellent (80+)
- Details : 1-3 phrases expliquant le resultat pour chaque categorie
- Tips : 2-5 conseils actionnables par categorie
- Summary : 2-3 phrases de synthese globale
- TopRecommendations : les 3-5 actions les plus impactantes
- Sois REALISTE : pas de scores parfaits sauf si vraiment justifie
- Reponds en francais
`;

// ================================================================
// MAIN EXPORT
// ================================================================

export const auditAnswerFirst = async (url: string, brandName?: string): Promise<AnswerFirstAuditResult> => {
  const apiKey = getApiKey();

  if (!apiKey) {
    console.warn("API_KEY not found or process.env unavailable, using simulation.");
    return fallbackSimulation(url, brandName);
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const userPrompt = `
      Audite la citabilite IA de cette URL :

      URL : ${url}
      ${brandName ? `MARQUE : ${brandName}` : ''}

      Analyse le contenu de la page et evalue chaque categorie selon les criteres definis.
      Le score global doit etre la moyenne ponderee :
      - answerFirst: 25%
      - schemaOrg: 20%
      - faqStructure: 15%
      - semanticHtml: 15%
      - contentFreshness: 10%
      - metaOptimization: 15%

      Reponds au format JSON strict selon le schema fourni.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userPrompt,
      config: {
        systemInstruction: AUDIT_SYSTEM_PROMPT,
        responseMimeType: 'application/json',
        responseSchema: buildResponseSchema(),
        temperature: 0.3,
      }
    });

    let output = response.text;
    if (!output) {
      throw new Error("Empty response from AI");
    }

    // Clean up potentially leaked markdown fences despite JSON mode
    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const parsed = JSON.parse(output);

    return {
      globalScore: parsed.globalScore,
      url,
      categories: {
        answerFirst: parsed.categories.answerFirst,
        schemaOrg: parsed.categories.schemaOrg,
        faqStructure: parsed.categories.faqStructure,
        semanticHtml: parsed.categories.semanticHtml,
        contentFreshness: parsed.categories.contentFreshness,
        metaOptimization: parsed.categories.metaOptimization,
      },
      summary: parsed.summary,
      topRecommendations: parsed.topRecommendations || [],
    };

  } catch (error) {
    console.error("Answer-First Audit failed:", error);
    return fallbackSimulation(url, brandName);
  }
};
